protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    modelBuilder.Entity<Product>(entity =>
    {
        entity.ToContainer("Products");

        // Preserve EF Core 8 discriminator property name ("Discriminator")
        // so existing documents and raw SQL queries (c.Discriminator) keep working.
        // EF Core 9 defaults to "$type".
        entity.HasDiscriminator<string>("Discriminator");

        // Preserve EF Core 8 compound id format ("Product|123")
        // so existing documents remain accessible via FindAsync / point-reads.
        // EF Core 9 defaults to key-only ids.
        entity.HasRootDiscriminatorInJsonId(true);
    });

    // REMOVED: .HasIndex() — EF Core 9 Cosmos provider throws at startup.
    // Manage indexes via the container's indexing policy in Azure Portal / Bicep / Terraform.
}

